function nextRelation(metadata, msg) {
    var out_list = [];
    switch (msg.method) {
        case "createGroup":
            out_list = ['createGroup']
            break;
            
        case "addDevToGroup":
            out_list = ['addDevToGroup']
            break;
            
        case "delDevFromGroup":
            out_list = ['delDevFromGroup']
            break;
            
        case "delGroup":
            out_list = ['delGroup']
            break;

        default:
            out_list = ['otherMethod']
            break;
    }
    return out_list;
}
return nextRelation(metadata, msg);

