function nextRelation(metadata, msg) {
    var KeysControl = ["bt","dim","h","s","l"]
    var out_list = [];
    var values = msg.params;

    var method = null;
    var hasValidControlField = false;
    var isInvalid = false;

    for (var key in values) {
        if (values.hasOwnProperty(key)) {
            var val = values[key];

            if (KeysControl.indexOf(key) != -1) {
                // field hợp lệ
                hasValidControlField = true;
                
                // check type number
                if (typeof val !== "number") {
                    isInvalid = true;
                    break;
                }

                // check integer
                if (val % 1 !== 0) {
                    isInvalid = true;
                    break;
                }

                // check range
                if (key === "dim") {
                    if (val < 0 || val > 100) {
                        isInvalid = true;
                        break;
                    }
                }

                if (key === "bt") {
                    if (val < 0 || val > 1) {
                        isInvalid = true;
                        break;
                    }
                }
            }
        }
    }

    if (hasValidControlField && !isInvalid) {
        method = "controlEntity";
    }

    switch (method) {
        case "controlEntity":
            out_list = ['controlEntity'];
            break;

        default:
            out_list = ['otherMethod'];
            break;
    }

    return out_list;
}

return nextRelation(metadata, msg);

