    msg: msg,
    metadata: metadata,
    msgType: msgType
};

function splitGroupByGateway(input) {

    // =====================================================
    // VALIDATE
    // =====================================================

    if (
        !input ||
        !input.params ||
        !input.params.devices ||
        !input.params.devices.length
    ) {
        return [];
    }

    var params = input.params;
    var devices = params.devices;

    // gatewayMap
    // {
    //    gatewayName: {
    //        devices: []
    //    }
    // }
    var gatewayMap = {};

    var i;

    // =====================================================
    // STEP 1: Group devices theo gateway
    // =====================================================

    for (i = 0; i < devices.length; i++) {

        var device = devices[i];

        if (!device || !device.gateway) {
            continue;
        }

        var gateway = device.gateway;

        if (!gatewayMap[gateway]) {
            gatewayMap[gateway] = {
                devices: []
            };
        }

        gatewayMap[gateway].devices.push(device);
    }

    // =====================================================
    // STEP 2: Build output
    // =====================================================

    var result = [];

    for (var gatewayKey in gatewayMap) {

        if (!gatewayMap.hasOwnProperty(gatewayKey)) {
            continue;
        }

        var item = gatewayMap[gatewayKey];

        result.push({
            method: input.method,

            params: {
                id: params.id,
                dormitoryId: params.dormitoryId,
                room: params.room,
                gateway: gatewayKey,
                name: params.name,
                // giữ nguyên devices
                devices: item.devices
            },

            timeout: input.timeout
        });
    }

    return result;
}

metadata.entityName = msg.params.id
metadata.entityName_Dormitory = msg.params.dormitoryId
metadata.entityName_Room = msg.params.room
metadata.lable = msg.params.name
msg = splitGroupByGateway(msg)
return { msg: msg, metadata: metadata, msgType: msgType };

